import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api';

export default function RatingPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [task, setTask] = useState(null);
  const [score, setScore] = useState(0);
  const [comment, setComment] = useState('');
  const [loading, setLoading] = useState(false);
  const [hover, setHover] = useState(0);

  useEffect(() => {
    api.get(`/tasks/${id}`).then(res => setTask(res.data)).catch(() => {});
  }, [id]);

  const handleSubmit = async () => {
    if (!score) return alert('Выберите оценку');
    setLoading(true);
    try {
      await api.post('/ratings', {
        task_id: parseInt(id),
        rated_id: task.helper_id,
        score,
        comment
      });
      navigate('/my-tasks');
    } catch (err) {
      alert(err.response?.data?.error || 'Ошибка');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container">
      <div className="page-header">
        <button className="back-btn" onClick={() => navigate(-1)}>← Назад</button>
        <span className="page-title">Rating</span>
      </div>

      <div style={{ padding: '32px 24px', textAlign: 'center' }}>
        {/* Avatar */}
        <div style={{
          width: 80, height: 80, borderRadius: '50%', background: '#e5e7eb',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 32, fontWeight: 700, margin: '0 auto 16px'
        }}>
          {task?.helper_name?.[0]?.toUpperCase() || '?'}
        </div>

        <h2 style={{ fontSize: 20, fontWeight: 800, marginBottom: 24, lineHeight: 1.4 }}>
          How was your experience with<br />
          <span style={{ color: 'var(--green)' }}>{task?.helper_name || '...'}</span>?
        </h2>

        {/* Stars */}
        <div className="star-rating" style={{ justifyContent: 'center', marginBottom: 24 }}>
          {[1, 2, 3, 4, 5].map(s => (
            <span
              key={s}
              onClick={() => setScore(s)}
              onMouseEnter={() => setHover(s)}
              onMouseLeave={() => setHover(0)}
              style={{
                cursor: 'pointer',
                filter: s <= (hover || score) ? 'none' : 'grayscale(1) opacity(0.4)',
                transform: s <= (hover || score) ? 'scale(1.15)' : 'scale(1)',
                transition: 'all 0.15s',
                fontSize: 36
              }}
            >
              ⭐
            </span>
          ))}
        </div>

        <div style={{ textAlign: 'left', marginBottom: 24 }}>
          <label style={{
            display: 'block', fontSize: 14, color: 'var(--text-muted)',
            marginBottom: 8, fontWeight: 600
          }}>
            Share your experience (optional)
          </label>
          <textarea
            style={{
              width: '100%', background: '#f1f5f0', border: '1.5px solid transparent',
              borderRadius: 12, padding: 14, fontSize: 15, resize: 'vertical',
              outline: 'none', fontFamily: 'inherit', minHeight: 100
            }}
            placeholder="Расскажите о помощнике..."
            value={comment}
            onChange={e => setComment(e.target.value)}
          />
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          <button className="btn-primary" onClick={handleSubmit} disabled={loading || !score}>
            {loading ? 'Отправляем...' : 'Submit review'}
          </button>
          <button className="btn-secondary" onClick={() => navigate('/my-tasks')}>
            Skip
          </button>
        </div>
      </div>
    </div>
  );
}
